// Server-only database module. Never imported from client code.
// This file uses Node-only modules (`node:*`, `better-sqlite3`) so it must
// only be loaded inside server boundaries (e.g. `routeLoader$`).

import Database from "better-sqlite3";
import { mkdirSync } from "node:fs";
import { dirname, resolve } from "node:path";

export interface SearchResultRow {
  rank: number;
  title: string;
  snippet: string;
  body: string;
}

export interface SearchPayload {
  query: string;
  results: SearchResultRow[];
  total: number;
}

export const DB_PATH = resolve(process.cwd(), "data", "app.db");

const SEED_DOCUMENTS: ReadonlyArray<{ title: string; body: string }> = [
  {
    title: "Introduction to SQLite",
    body: "SQLite is a lightweight embedded database engine used in many applications.",
  },
  {
    title: "Full Text Search with FTS5",
    body: "The FTS5 extension enables fast full text search over documents using an inverted index.",
  },
  {
    title: "Getting Started with Qwik",
    body: "Qwik is a resumable web framework that delivers instant loading web applications.",
  },
  {
    title: "Reactive State in Qwik",
    body: "Use signals and stores to manage reactive state inside Qwik components.",
  },
  {
    title: "Building REST APIs",
    body: "Design clean REST endpoints to serve JSON data to client applications.",
  },
  {
    title: "Database Indexing Basics",
    body: "Indexes speed up query performance in relational databases like SQLite and Postgres.",
  },
  {
    title: "Server Side Rendering",
    body: "Server side rendering improves performance and search engine visibility for web applications.",
  },
  {
    title: "Web Performance Tips",
    body: "Reduce JavaScript to improve web performance and loading speed for users.",
  },
];

let cachedDb: Database.Database | null = null;
let initialized = false;

function ensureSchema(db: Database.Database): void {
  db.exec(
    "CREATE VIRTUAL TABLE IF NOT EXISTS documents USING fts5(title, body)",
  );
}

function seedIfEmpty(db: Database.Database): void {
  const countRow = db
    .prepare("SELECT COUNT(*) AS c FROM documents")
    .get() as { c: number };
  if (countRow.c > 0) {
    return;
  }
  const insert = db.prepare(
    "INSERT INTO documents (title, body) VALUES (?, ?)",
  );
  const tx = db.transaction((rows: ReadonlyArray<{ title: string; body: string }>) => {
    for (const row of rows) {
      insert.run(row.title, row.body);
    }
  });
  tx(SEED_DOCUMENTS);
}

function initDatabase(db: Database.Database): void {
  ensureSchema(db);
  seedIfEmpty(db);
  initialized = true;
}

function getDb(): Database.Database {
  if (cachedDb && initialized) {
    return cachedDb;
  }
  mkdirSync(dirname(DB_PATH), { recursive: true });
  const db = new Database(DB_PATH);
  // Ensure FTS5 features used below (highlight, snippet, bm25) are available.
  db.exec("PRAGMA journal_mode = WAL");
  initDatabase(db);
  cachedDb = db;
  return db;
}

/**
 * Run a full-text search against the documents FTS5 table.
 * Returns ranked results with highlighted snippets and the total match count.
 *
 * `rawQuery` is the user-supplied query string from the URL. It is wrapped
 * in double quotes to escape any FTS5 special characters so a malformed
 * query never crashes the loader. FTS5 still tokenizes the contents of
 * the quoted phrase and matches documents containing any of those terms.
 */
export function searchDocuments(rawQuery: string): SearchPayload {
  const query = rawQuery.trim();
  if (!query) {
    return { query: "", results: [], total: 0 };
  }

  const db = getDb();

  // Escape any embedded double quotes and wrap the whole query so FTS5
  // does not interpret operators like `*`, `AND`, `OR`, or `NEAR`.
  const escaped = query.replace(/"/g, '""');
  const ftsQuery = `"${escaped}"`;

  // Use bm25() explicitly (rank is equivalent) and highlight() to wrap
  // matches in <mark>...</mark>. snippet() could be used as well, but
  // the highlight() function on the body column already produces a
  // snippet-like string with all matches tagged.
  const stmt = db.prepare<
    [string],
    {
      title: string;
      body: string;
      rank: number;
      snippet: string;
    }
  >(`
    SELECT
      title,
      body,
      bm25(documents) AS rank,
      highlight(documents, 1, '<mark>', '</mark>') AS snippet
    FROM documents
    WHERE documents MATCH ?
    ORDER BY rank
  `);

  const rows = stmt.all(ftsQuery) as Array<{
    title: string;
    body: string;
    rank: number;
    snippet: string;
  }>;

  const results: SearchResultRow[] = rows.map((row, index) => ({
    rank: index + 1,
    title: row.title,
    body: row.body,
    snippet: row.snippet,
  }));

  return {
    query,
    results,
    total: results.length,
  };
}

// Eagerly initialize the database so seeding happens before the first request.
getDb();

import {
  $,
  component$,
  useSignal,
  useTask$,
  useVisibleTask$,
} from "@builder.io/qwik";
import type { DocumentHead } from "@builder.io/qwik-city";
import { routeLoader$ } from "@builder.io/qwik-city";

import { searchDocuments } from "../lib/db";

// Server-only route loader. Runs on every request to "/" and reads the
// `q` query parameter via the RequestEvent API. Returns the search
// payload (or an empty payload when no query is supplied).
export const useSearch = routeLoader$((requestEvent) => {
  const raw = requestEvent.query.get("q") ?? "";
  return searchDocuments(raw);
});

export default component$(() => {
  const search = useSearch();
  const inputRef = useSignal<HTMLInputElement>();

  // Keep the visible input value in sync with the URL `q` parameter so
  // back/forward navigation and direct loads are reflected in the box.
  useTask$(({ track }) => {
    track(() => search.value.query);
    const el = inputRef.value;
    if (el && el.value !== search.value.query) {
      el.value = search.value.query;
    }
  });

  // Debounced URL update: as the user types, push the new `q` value into
  // the URL after a short idle period. We push the history entry rather
  // than replacing it so back/forward still works per keystroke.
  // eslint-disable-next-line qwik/no-use-visible-task
  useVisibleTask$(({ cleanup }) => {
    const el = inputRef.value;
    if (!el) return;

    let debounceId: ReturnType<typeof setTimeout> | undefined;
    let lastSubmitted = el.value;

    const submit = (next: string) => {
      lastSubmitted = next;
      const url = new URL(window.location.href);
      if (next.trim() === "") {
        url.searchParams.delete("q");
      } else {
        url.searchParams.set("q", next);
      }
      window.history.pushState({}, "", url.toString());
      // Trigger a navigation event so the route loader re-runs with the
      // new query string. `popstate` would only fire for back/forward,
      // so we dispatch it manually after pushing state.
      window.dispatchEvent(new PopStateEvent("popstate"));
    };

    const onInput = (event: Event) => {
      const target = event.target as HTMLInputElement;
      const value = target.value;
      if (debounceId !== undefined) {
        clearTimeout(debounceId);
      }
      debounceId = setTimeout(() => {
        if (value !== lastSubmitted) {
          submit(value);
        }
      }, 200);
    };

    const onPopState = () => {
      const url = new URL(window.location.href);
      const next = url.searchParams.get("q") ?? "";
      if (el.value !== next) {
        el.value = next;
        lastSubmitted = next;
      }
    };

    el.addEventListener("input", onInput);
    window.addEventListener("popstate", onPopState);

    cleanup(() => {
      if (debounceId !== undefined) clearTimeout(debounceId);
      el.removeEventListener("input", onInput);
      window.removeEventListener("popstate", onPopState);
    });
  });

  // Immediate (non-debounced) submit handler for the form. Used when the
  // user presses Enter or the submit button so navigation feels instant.
  const onSubmit = $((event: SubmitEvent) => {
    event.preventDefault();
    const el = inputRef.value;
    if (!el) return;
    const url = new URL(window.location.href);
    const value = el.value;
    if (value.trim() === "") {
      url.searchParams.delete("q");
    } else {
      url.searchParams.set("q", value);
    }
    window.history.pushState({}, "", url.toString());
    window.dispatchEvent(new PopStateEvent("popstate"));
  });

  const payload = search.value;

  return (
    <main class="container">
      <h1>Full-Text Document Search</h1>

      <form class="search-form" preventdefault:submit onSubmit$={onSubmit}>
        <input
          ref={inputRef}
          type="search"
          name="q"
          autoComplete="off"
          placeholder="Search documents..."
          aria-label="Search documents"
          defaultValue={payload.query}
        />
        <button type="submit">Search</button>
      </form>

      {payload.query.trim() === "" ? (
        <p class="empty-state">Enter a search term to find documents.</p>
      ) : payload.results.length === 0 ? (
        <p class="empty-state">
          No results found for <strong>{payload.query}</strong>.
        </p>
      ) : (
        <>
          <p class="result-count" data-testid="result-count">
            {payload.total} results
          </p>
          <ol class="results">
            {payload.results.map((result) => (
              <li key={result.rank} class="result">
                <div class="result-meta">
                  <span class="result-rank">#{result.rank}</span>
                  <h2 class="result-title">{result.title}</h2>
                </div>
                <p
                  class="result-snippet"
                  // FTS5 highlight() returns pre-escaped HTML with
                  // <mark> tags around matches. The body content comes
                  // from our seed corpus (no user-supplied HTML), so
                  // rendering it raw is safe here.
                  dangerouslySetInnerHTML={result.snippet}
                />
              </li>
            ))}
          </ol>
        </>
      )}
    </main>
  );
});

export const head: DocumentHead = {
  title: "Full-Text Document Search",
  meta: [
    {
      name: "description",
      content:
        "Search a small document corpus with SQLite FTS5 and Qwik City SSR.",
    },
  ],
};

